60	function buildContextPackInsert(plan: OraclePromptPlan) {
61	  return {
62	    taskType: plan.taskType,
63	    routeId: plan.routeId,
64	    promptVersion: plan.promptVersion,
65	    schemaVersion: plan.schemaVersion ?? null,
66	    stablePrefixHash: plan.metadata.stablePrefixHash,
67	    semiStableContextHash: plan.metadata.semiStableContextHash ?? null,
68	    retrievedContextHash: plan.metadata.retrievedContextHash ?? null,
69	    dynamicInputHash: plan.metadata.dynamicInputHash,
70	    toolSchemaHash: plan.metadata.toolSchemaHash ?? null,
71	    outputSchemaHash: plan.metadata.outputSchemaHash ?? null,
72	    blocksJson: plan.blocks.map((b) => ({
73	      id: b.id,
74	      label: b.label,
75	      kind: b.kind,
76	      hash: b.hash,
77	      tokenEstimate: b.tokenEstimate ?? null,
78	      cacheEligible: b.cacheEligible,
79	      reasonIncluded: b.reasonIncluded,
80	    })),
81	    includedDocumentChunkIds: plan.metadata.includedDocumentChunkIds ?? null,
82	  };
83	}
