85	function buildDocumentCorpus(chunks: ChunkRow[]): string {
86	  return chunks
87	    .map((chunk) => {
88	      const page = chunk.pageNumber ? ` page=${chunk.pageNumber}` : '';
89	      return `--- Document Chunk ID: ${chunk.id} index=${chunk.chunkIndex}${page} ---\n${chunk.rawText}`;
90	    })
91	    .join('\n\n');
92	}
