94	function normalizeOutlineRefs(
95	  outline: SourceOutlineOutput,
96	  chunkIds: Set<string>,
97	): SourceOutlineOutput {
98	  const validRefs = outline.refs.filter((ref) => chunkIds.has(ref.chunkId));
99	  const groups = outline.groups
100	    .map((group) => ({
101	      ...group,
102	      chunkIds: Array.from(new Set(group.chunkIds.filter((id) => chunkIds.has(id)))),
103	    }))
104	    .filter((group) => group.chunkIds.length > 0);
105	
106	  return {
107	    ...outline,
108	    refs: validRefs,
109	    groups,
110	    entities: outline.entities.map((entity) => ({
111	      ...entity,
112	      chunkIds: entity.chunkIds?.filter((id) => chunkIds.has(id)),
113	    })),
114	    terms: outline.terms.map((term) => ({
115	      ...term,
116	      chunkIds: term.chunkIds?.filter((id) => chunkIds.has(id)),
117	    })),
118	    stages: outline.stages.map((stage) => ({
119	      ...stage,
120	      chunkIds: stage.chunkIds?.filter((id) => chunkIds.has(id)),
121	    })),
122	  };
123	}
