125	async function supersedeExistingDocumentOutlines(db: OracleDb, documentId: string): Promise<void> {
126	  const existing = await db
127	    .select({ outlineId: sourceOutlineSources.sourceOutlineId })
128	    .from(sourceOutlineSources)
129	    .where(
130	      and(
131	        eq(sourceOutlineSources.sourceType, 'document'),
132	        eq(sourceOutlineSources.documentId, documentId),
133	      ),
134	    );
135	
136	  const ids = Array.from(new Set(existing.map((row) => row.outlineId)));
137	  if (ids.length === 0) return;
138	
139	  await db
140	    .update(sourceOutlines)
141	    .set({ status: 'superseded', updatedAt: new Date() })
142	    .where(and(inArray(sourceOutlines.id, ids), eq(sourceOutlines.status, 'provisional')));
143	}
