145	async function persistOutline(args: {
146	  db: OracleDb;
147	  documentId: string;
148	  sourceHash: string;
149	  outline: SourceOutlineOutput;
150	  modelRunId: string | null;
151	  contextPackId: string | null;
152	}): Promise<string> {
153	  const { db, documentId, sourceHash, outline, modelRunId, contextPackId } = args;
154	
155	  await supersedeExistingDocumentOutlines(db, documentId);
156	
157	  const groupTexts = outline.groups.map((group) =>
158	    [group.title, group.description, group.recommendedLenses?.join(', ')]
159	      .filter(Boolean)
160	      .join('\n'),
161	  );
162	  let groupEmbeddings: number[][] = [];
163	  if (groupTexts.length > 0) {
164	    try {
165	      groupEmbeddings = (await embedMany(groupTexts)).vectors;
166	    } catch (err) {
167	      console.warn('[source-outline] group embedding failed; storing groups without vectors', err);
168	      groupEmbeddings = [];
169	    }
170	  }
171	
172	  const [outlineRow] = await db
173	    .insert(sourceOutlines)
174	    .values({
175	      sourceType: 'document',
176	      status: 'provisional',
177	      outlineVersion: SOURCE_OUTLINE_PROMPT_VERSION,
178	      modelRunId,
179	      contextPackId,
180	      sourceHash,
181	      outlineJson: outline,
182	      summary: outline.summary,
183	      budgetJson: outline.budget,
184	    })
185	    .returning({ id: sourceOutlines.id });
186	  if (!outlineRow) throw new Error('[source-outline] failed to insert source_outlines row');
187	
188	  await db.insert(sourceOutlineSources).values({
189	    sourceOutlineId: outlineRow.id,
190	    sourceType: 'document',
191	    documentId,
192	    sourceHash,
193	  });
194	
195	  const refRows = outline.refs.map((ref) => ({
196	    sourceOutlineId: outlineRow.id,
197	    outlineElementId: null,
198	    refType: 'document_chunk',
199	    documentChunkId: ref.chunkId,
200	    refRole: ref.role,
201	    metadataJson: ref.note ? { note: ref.note } : null,
202	  }));
203	  if (refRows.length > 0) {
204	    await db.insert(sourceOutlineSourceRefs).values(refRows);
205	  }
206	
207	  for (let i = 0; i < outline.groups.length; i++) {
208	    const group = outline.groups[i]!;
209	    const [groupRow] = await db
210	      .insert(sourceGroups)
211	      .values({
212	        sourceOutlineId: outlineRow.id,
213	        groupType: group.groupType,
214	        title: group.title,
215	        description: group.description ?? null,
216	        embedding: groupEmbeddings[i] ?? null,
217	        sortOrder: group.sortOrder ?? i,
218	        metadataJson: {
219	          elementId: group.elementId,
220	          recommendedLenses: group.recommendedLenses ?? [],
221	          uncertainty: group.uncertainty ?? null,
222	        },
223	      })
224	      .returning({ id: sourceGroups.id });
225	    if (!groupRow) continue;
226	
227	    await db.insert(sourceGroupItems).values(
228	      group.chunkIds.map((chunkId, index) => ({
229	        sourceGroupId: groupRow.id,
230	        itemType: 'document_chunk',
231	        documentChunkId: chunkId,
232	        sortOrder: index,
233	      })),
234	    );
235	  }
236	
237	  return outlineRow.id;
238	}
