248	async function triggerDocumentLensFanout(args: {
249	  db: OracleDb;
250	  documentId: string;
251	  outlineId: string;
252	}): Promise<{
253	  triggered: number;
254	  planned: number;
255	  skipped: Array<{ sourceGroupId?: string; groupTitle?: string; lens?: string; reason: string }>;
256	}> {
257	  const plan = await buildLensDispatchPlan(args.db, args.outlineId);
258	  let triggered = 0;
259	  for (const selected of plan.selected) {
260	    await tasks
261	      .trigger('document-lens-extraction', {
262	        documentId: args.documentId,
263	        sourceOutlineId: args.outlineId,
264	        sourceGroupId: selected.sourceGroupId,
265	        lens: selected.lens,
266	      })
267	      .then(() => {
268	        triggered += 1;
269	      })
270	      .catch((err) =>
271	        console.warn('[source-outline] failed to trigger document lens extraction', {
272	          sourceGroupId: selected.sourceGroupId,
273	          lens: selected.lens,
274	          err,
275	        }),
276	      );
277	  }
278	  return { triggered, planned: plan.selected.length, skipped: plan.skipped };
279	}
