281	async function generateDocumentOutline(documentId: string, force: boolean, triggerRunId: string) {
282	  const db = getDirectDb();
283	
284	  const [doc] = await db
285	    .select({
286	      id: documents.id,
287	      fileName: documents.fileName,
288	      fileType: documents.fileType,
289	      status: documents.status,
290	      context: documents.context,
291	    })
292	    .from(documents)
293	    .where(eq(documents.id, documentId))
294	    .limit(1);
295	  if (!doc) return { documentId, status: 'skipped_not_found' as const };
296	
297	  const chunks = await db
298	    .select({
299	      id: documentChunks.id,
300	      chunkIndex: documentChunks.chunkIndex,
301	      pageNumber: documentChunks.pageNumber,
302	      rawText: documentChunks.rawText,
303	      contentHash: documentChunks.contentHash,
304	    })
305	    .from(documentChunks)
306	    .where(eq(documentChunks.documentId, documentId))
307	    .orderBy(documentChunks.chunkIndex);
308	  if (chunks.length === 0) return { documentId, status: 'skipped_no_chunks' as const };
309	
310	  const documentCorpus = buildDocumentCorpus(chunks);
311	  const sourceHash = sha256(
312	    JSON.stringify({
313	      documentId,
314	      chunks: chunks.map((chunk) => [chunk.id, chunk.chunkIndex, chunk.contentHash, chunk.rawText]),
315	    }),
316	  );
317	
318	  if (!force) {
319	    const [existing] = await db
320	      .select({ id: sourceOutlines.id })
321	      .from(sourceOutlines)
322	      .innerJoin(sourceOutlineSources, eq(sourceOutlineSources.sourceOutlineId, sourceOutlines.id))
323	      .where(
324	        and(
325	          eq(sourceOutlineSources.documentId, documentId),
326	          eq(sourceOutlineSources.sourceType, 'document'),
327	          eq(sourceOutlines.status, 'provisional'),
328	          eq(sourceOutlines.sourceHash, sourceHash),
329	        ),
330	      )
331	      .orderBy(desc(sourceOutlines.createdAt))
332	      .limit(1);
333	    if (existing) {
334	      const lensFanout = await triggerDocumentLensFanout({
335	        db,
336	        documentId,
337	        outlineId: existing.id,
338	      });
339	      const followups =
340	        lensFanout.planned === 0
341	          ? await triggerMacroFollowupsOnce({
342	              db,
343	              documentId,
344	              outlineId: existing.id,
345	              groupCount: await countSourceOutlineGroups(db, existing.id),
346	              reason: 'source_outline_no_lens_jobs',
347	            })
348	          : await markMacroPending(db, documentId).then(() => ({
349	              triggered: false,
350	              reason: 'deferred_until_lens_fanout_complete',
351	            }));
352	      return {
353	        documentId,
354	        status: 'skipped_existing' as const,
355	        outlineId: existing.id,
356	        lensFanout,
357	        macroFollowups: followups,
358	      };
359	    }
360	  }
361	
362	  const [jobRun] = await db
363	    .insert(jobRuns)
364	    .values({
365	      triggerRunId,
366	      jobType: 'source-outline',
367	      status: 'running',
368	      startedAt: new Date(),
369	      inputJson: { documentId, force },
370	    })
371	    .returning({ id: jobRuns.id });
372	  if (!jobRun) throw new Error('[source-outline] failed to insert job_runs row');
373	
374	  try {
375	    const client = new OracleAIClient({ adapters: buildStandardAdapters() });
376	    const resolved = await resolveRouteCandidates(db, 'macro');
377	    for (const skipped of resolved.skipped) {
378	      console.warn('[source-outline] skipped general route candidate', skipped);
379	    }
380	    const routeCandidates = resolved.candidates;
381	    const route = routeCandidates[0]!.route;
382	    const chunkIds = chunks.map((chunk) => chunk.id);
383	
384	    const blocks = [
385	      makeBlock({
386	        id: 'source-outline-system',
387	        label: 'Source outline system prompt',
388	        kind: 'stable_system',
389	        content: SOURCE_OUTLINE_SYSTEM_PROMPT,
390	        reasonIncluded: `source outline prompt v${SOURCE_OUTLINE_PROMPT_VERSION}`,
391	      }),
392	      makeBlock({
393	        id: 'document-metadata',
394	        label: 'Document metadata',
395	        kind: 'semi_stable_domain_context',
396	        content: [
397	          `Document name: ${doc.fileName}`,
398	          `File type: ${doc.fileType}`,
399	          doc.context ? `Uploader context:\n${doc.context}` : null,
400	        ]
401	          .filter(Boolean)
402	          .join('\n\n'),
403	        reasonIncluded: 'document-level context for macro outline',
404	      }),
405	      makeBlock({
406	        id: 'document-chunks',
407	        label: 'Document chunks',
408	        kind: 'retrieved_context',
409	        content: documentCorpus,
410	        reasonIncluded: `${chunks.length} persisted document chunks; outline refs must use these chunk IDs`,
411	      }),
412	      makeBlock({
413	        id: 'source-outline-request',
414	        label: 'Source outline request',
415	        kind: 'dynamic_input',
416	        content:
417	          'Create a provisional macro outline for this document. Identify process stages, handoffs, exception branches, terms, entities, source groups, recommended extraction lenses, and open questions. Use only provided document chunk IDs in refs and groups.',
418	        reasonIncluded: 'request current outline output',
419	      }),
420	    ];
421	
422	    const plan = client.compile({
423	      taskType: 'source_outline',
424	      routeId: route.routeId,
425	      promptVersion: SOURCE_OUTLINE_PROMPT_VERSION,
426	      blocks,
427	      observability: { includedDocumentChunkIds: chunkIds },
428	    });
429	    const [contextPack] = await db
430	      .insert(oracleContextPacks)
431	      .values(buildContextPackInsert(plan))
432	      .returning({ id: oracleContextPacks.id });
433	    if (!contextPack) throw new Error('[source-outline] failed to insert context pack');
434	
435	    const started = Date.now();
436	    let modelRunId: string | null = null;
437	    const result = await client
438	      .runObject<SourceOutlineOutput>({
439	        taskType: 'source_outline',
440	        routeId: route.routeId,
441	        promptVersion: SOURCE_OUTLINE_PROMPT_VERSION,
442	        blocks,
443	        schema: SourceOutlineSchema,
444	        observability: { includedDocumentChunkIds: chunkIds },
445	        providerOptions: { maxOutputTokens: 16_000 },
446	        routeCandidates,
447	      })
448	      .catch(async (err) => {
449	        await logAllCandidatesFailedAttempts({
450	          db,
451	          error: err,
452	          taskType: 'source-outline',
453	          slot: 'macro',
454	          contextPackId: contextPack.id,
455	        }).catch((logErr) =>
456	          console.error('[source-outline] failed to record failed model attempts', logErr),
457	        );
458	        throw err;
459	      });
460	
461	    const actualRouteId = result.routeId ?? route.routeId;
462	    const actualProvider = result.provider ?? route.provider;
463	    const actualModelId = result.modelId ?? route.modelId;
464	    const [modelRun] = await db
465	      .insert(modelRuns)
466	      .values({
467	        taskType: 'source-outline',
468	        model: actualModelId,
469	        provider: actualProvider,
470	        promptVersion: SOURCE_OUTLINE_PROMPT_VERSION,
471	        inputHash: plan.metadata.stablePrefixHash,
472	        inputTokens: result.usage.inputTokens ?? null,
473	        outputTokens: result.usage.outputTokens ?? null,
474	        latencyMs: Date.now() - started,
475	        success: result.validation.ok,
476	        error: result.validation.ok ? null : result.validation.error.message,
477	      })
478	      .returning({ id: modelRuns.id });
479	    if (!modelRun) throw new Error('[source-outline] failed to insert model_runs row');
480	    modelRunId = modelRun.id;
481	
482	    await db.insert(modelRunUsageDetails).values({
483	      modelRunId,
484	      contextPackId: contextPack.id,
485	      routeId: actualRouteId,
486	      inputTokens: result.usage.inputTokens ?? null,
487	      cachedInputTokens: result.usage.cachedInputTokens ?? null,
488	      cacheWriteTokens: result.usage.cacheWriteTokens ?? null,
489	      outputTokens: result.usage.outputTokens ?? null,
490	      reasoningTokens: result.usage.reasoningTokens ?? null,
491	      providerRequestId: result.usage.providerRequestId ?? null,
492	      rawUsageJson: result.usage.rawUsageJson ?? null,
493	    });
494	    await logModelRunAttempts({
495	      db,
496	      metadata: result,
497	      taskType: 'source-outline',
498	      slot: 'macro',
499	      contextPackId: contextPack.id,
500	      modelRunId,
501	    });
502	    await db
503	      .update(oracleContextPacks)
504	      .set({ modelRunId })
505	      .where(eq(oracleContextPacks.id, contextPack.id));
506	
507	    if (!result.validation.ok) {
508	      throw new Error(
509	        '[source-outline] model output failed Zod schema validation: ' +
510	          result.validation.error.message,
511	      );
512	    }
513	
514	    const outline = normalizeOutlineRefs(result.object, new Set(chunkIds));
515	    const outlineId = await persistOutline({
516	      db,
517	      documentId,
518	      sourceHash,
519	      outline,
520	      modelRunId,
521	      contextPackId: contextPack.id,
522	    });
523	    const lensFanout = await triggerDocumentLensFanout({
524	      db,
525	      documentId,
526	      outlineId,
527	    });
528	    const followups =
529	      lensFanout.planned === 0
530	        ? await triggerMacroFollowupsOnce({
531	            db,
532	            documentId,
533	            outlineId,
534	            groupCount: outline.groups.length,
535	            reason: 'source_outline_no_lens_jobs',
536	          })
537	        : await markMacroPending(db, documentId).then(() => ({
538	            triggered: false,
539	            reason: 'deferred_until_lens_fanout_complete',
540	          }));
541	
542	    await db
543	      .update(jobRuns)
544	      .set({
545	        status: 'complete',
546	        finishedAt: new Date(),
547	        outputJson: {
548	          documentId,
549	          outlineId,
550	          groupCount: outline.groups.length,
551	          refCount: outline.refs.length,
552	          lensFanout,
553	          macroFollowups: followups,
554	        },
555	      })
556	      .where(eq(jobRuns.id, jobRun.id));
557	
558	    return { documentId, status: 'outlined' as const, outlineId };
559	  } catch (err) {
560	    await db
561	      .update(jobRuns)
562	      .set({
563	        status: 'failed',
564	        finishedAt: new Date(),
565	        error: err instanceof Error ? err.message : String(err),
566	      })
567	      .where(eq(jobRuns.id, jobRun.id));
568	    // Outline itself failed => no holistic layer at all for this document.
569	    await markMacroFailed(db, documentId);
570	    throw err;
571	  }
572	}
