1	export type MacroRelationshipStatus =
2	  | 'pending_review'
3	  | 'blocked_pending_support'
4	  | 'approved'
5	  | 'rejected'
6	  | 'needs_review'
7	  | 'stale_support'
8	  | 'superseded';
9	
10	export type SupportClaimStatus = 'approved' | 'pending_review' | 'rejected' | 'superseded' | string;
11	
12	export function allMacroSupportApproved(statuses: readonly SupportClaimStatus[]): boolean {
13	  return statuses.length >= 2 && statuses.every((status) => status === 'approved');
14	}
15	
16	export function statusForGeneratedMacroRelationship(statuses: readonly SupportClaimStatus[]): MacroRelationshipStatus {
17	  return allMacroSupportApproved(statuses) ? 'pending_review' : 'blocked_pending_support';
18	}
19	
20	export function statusAfterDroppingMacroSupport(statuses: readonly SupportClaimStatus[]): MacroRelationshipStatus {
21	  return allMacroSupportApproved(statuses) ? 'pending_review' : 'needs_review';
22	}
23	
24	export function statusAfterMacroSupportChange(args: {
25	  currentStatus: MacroRelationshipStatus;
26	  supportStatuses: readonly SupportClaimStatus[];
27	}): MacroRelationshipStatus {
28	  if (args.currentStatus === 'approved' && !allMacroSupportApproved(args.supportStatuses)) {
29	    return 'stale_support';
30	  }
31	  if (
32	    (args.currentStatus === 'blocked_pending_support' || args.currentStatus === 'needs_review') &&
33	    allMacroSupportApproved(args.supportStatuses)
34	  ) {
35	    return 'pending_review';
36	  }
37	  return args.currentStatus;
38	}
